def psnr_to_mse(psnr):
    import math
    def psnr_to_mse(psnr):
        k = -0.1 * math.log(10.0)
        # handle scalars
        if isinstance(psnr, (int, float)):
            return math.exp(k * psnr)
        # handle iterables (lists, tuples, numpy arrays, etc.)
        try:
            iterator = iter(psnr)
        except TypeError:
            # fallback for unexpected types
            return math.exp(k * psnr)
        return [math.exp(k * float(x)) for x in iterator]

