            if na == 0:
                return np.ones(b.shape[0])
            an = a / na
            bn = b / np.linalg.norm(b, axis=1, keepdims=True)
            bn = np.where(np.isfinite(bn), bn, 0.0)
            cos = bn.dot(an)
            cos = np.clip(cos, -1.0, 1.0)
            return 1.0 - cos
        else:
            raise KeyError("b must be a vector or 2D matrix")

