    def flatten_dict(d: dict, parent_key: str = "", sep: str = "/") -> dict:
        result = {}
        def _flatten(obj, base):
            if not isinstance(obj, Mapping):
                if base:
                    result[base] = obj
                return
            if not obj and base:
                result[base] = obj
                return
            for k, v in obj.items():
                key = base + sep + str(k) if base else str(k)
                _flatten(v, key)
        _flatten(d, parent_key)
        return result

