            for ln in textwrap.dedent(seg).splitlines():
                lines_out.append(ln)
        # strip leading/trailing blank lines
        while lines_out and lines_out[0].strip()=="":
            lines_out.pop(0)
        while lines_out and lines_out[-1].strip()=="":
