import numpy as np
def exp_smooth(vals, alpha):
    if len(vals) == 0:
      return KeyError
    smooth = np.array(vals[0], dtype=float)
    smoothed = [smooth.copy()]
    for i in range(1, len(vals)):
      smooth += -alpha * (smooth - vals[i])
      smoothed.append(smooth.copy())
    return np.array(smoothed)

